// 🧠 제4장: 데이터 구조화 — v5.1 메서드 구현 (Method Implementation & impl)
//
// 설계 철학:
// "데이터의 형체(필드)에 정신(기능)을 불어넣는 단계"
//
// v5.0: 구조체의 정의 (형체 만들기)
// v5.1: 메서드의 구현 (정신 부여) ← 여기!
//
// 핵심:
// - impl 블록: 구조체의 메서드를 한곳에 모음
// - self: 구조체 인스턴스 자신을 나타냄
// - 세 가지 형태: &self (읽기), &mut self (수정), self (소유권 이전)
//
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

/// 섹션 1: 기초 메서드 — self의 세 가지 형태
///
/// 메서드: 구조체에 속한 함수
/// self의 형태에 따라 기능이 결정됨
mod section_1_basic_methods {
    #[derive(Debug)]
    pub struct System {
        pub name: String,
        pub status: String,
        pub load: u8,
    }

    impl System {
        /// 연관 함수: new (생성자)
        /// 인스턴스 없이 호출 가능: System::new("...")
        /// System 타입 자체를 반환
        pub fn new(name: &str) -> System {
            System {
                name: String::from(name),
                status: String::from("IDLE"),
                load: 0,
            }
        }

        /// 메서드 1: &self 형태
        /// 데이터를 읽기만 함 (불변 참조)
        /// 소유권을 가져오지 않으므로 여러 번 호출 가능
        pub fn display_status(&self) {
            println!("  📊 [{}] 상태: {}, 부하: {}%",
                     self.name, self.status, self.load);
        }

        /// 메서드 2: &mut self 형태
        /// 내부 필드를 수정함 (가변 참조)
        /// 호출 시 인스턴스가 mut으로 선언되어야 함
        pub fn activate(&mut self) {
            self.status = String::from("ACTIVE");
            self.load = 45;
            println!("  ⚙️ 시스템 '{}' 가동 시작!", self.name);
        }

        /// 메서드 3: self 형태
        /// 소유권을 완전히 가져옴
        /// 메서드 실행 후 인스턴스가 해제됨
        /// "최후의 행동"에 사용 (예: 시스템 종료)
        pub fn shutdown(self) {
            println!("  🔴 시스템 '{}' 종료 중...", self.name);
            println!("  💀 인스턴스 메모리 해제됨");
            // self가 drop되면서 내부 String도 정리됨
        }
    }

    pub fn demonstrate() {
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!("📚 섹션 1: 기초 메서드 — self의 세 가지 형태");
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

        println!("1️⃣ 연관 함수로 인스턴스 생성:");
        let mut system = System::new("GOGS-Alpha");
        println!("   생성됨: {:?}\n", system);

        println!("2️⃣ &self 메서드 호출 (읽기만):");
        system.display_status();
        system.display_status();  // ✅ 여러 번 호출 가능
        println!("   ✅ 소유권 유지, 여러 번 호출 가능\n");

        println!("3️⃣ &mut self 메서드 호출 (수정):");
        system.activate();
        system.display_status();
        println!("   ✅ 내부 필드 수정됨\n");

        println!("4️⃣ self 메서드 호출 (소유권 이전):");
        system.shutdown();
        // println!("{:?}", system);  // ❌ 오류! system은 이미 해제됨
        println!("   ✅ 인스턴스가 메모리에서 해제됨\n");
    }
}

/// 섹션 2: 메서드 체이닝
///
/// &mut self를 반환하는 메서드를 통해
/// 여러 메서드를 연속으로 호출 가능
mod section_2_method_chaining {
    #[derive(Debug)]
    pub struct DataProcessor {
        pub data: String,
        pub processed: bool,
        pub encrypted: bool,
    }

    impl DataProcessor {
        pub fn new(data: &str) -> DataProcessor {
            DataProcessor {
                data: String::from(data),
                processed: false,
                encrypted: false,
            }
        }

        /// 체이닝을 위해 &mut self를 반환
        pub fn process(&mut self) -> &mut Self {
            self.processed = true;
            println!("  🔄 데이터 처리 중...");
            self
        }

        pub fn encrypt(&mut self) -> &mut Self {
            self.encrypted = true;
            println!("  🔐 데이터 암호화 중...");
            self
        }

        pub fn save(&mut self) -> &mut Self {
            println!("  💾 데이터 저장 중...");
            self
        }

        pub fn report(&self) {
            println!("  📋 처리됨: {}, 암호화됨: {}",
                     self.processed, self.encrypted);
        }
    }

    pub fn demonstrate() {
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!("📚 섹션 2: 메서드 체이닝");
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

        let mut processor = DataProcessor::new("Important Data");

        println!("1️⃣ 일반적인 호출:");
        processor.process();
        processor.encrypt();
        processor.save();
        processor.report();
        println!("");

        println!("2️⃣ 메서드 체이닝:");
        let mut processor2 = DataProcessor::new("Critical Data");
        processor2
            .process()
            .encrypt()
            .save();
        processor2.report();
        println!("\n   ✅ 여러 메서드를 한 줄로 호출\n");
    }
}

/// 섹션 3: 여러 impl 블록
///
/// 하나의 구조체에 대해 여러 impl 블록 작성 가능
/// 관심사를 분리하여 가독성 향상
mod section_3_multiple_impl {
    pub struct User {
        pub username: String,
        pub email: String,
        pub age: u32,
    }

    // impl 블록 1: 생성 관련 메서드
    impl User {
        pub fn new(username: &str, email: &str, age: u32) -> User {
            User {
                username: String::from(username),
                email: String::from(email),
                age,
            }
        }

        pub fn from_username(username: &str) -> User {
            User {
                username: String::from(username),
                email: String::from("unknown@example.com"),
                age: 0,
            }
        }
    }

    // impl 블록 2: 정보 조회 메서드
    impl User {
        pub fn display_info(&self) {
            println!("  👤 사용자: {}", self.username);
            println!("  📧 이메일: {}", self.email);
            println!("  🎂 나이: {}", self.age);
        }

        pub fn is_adult(&self) -> bool {
            self.age >= 18
        }
    }

    // impl 블록 3: 수정 메서드
    impl User {
        pub fn update_email(&mut self, new_email: &str) {
            self.email = String::from(new_email);
            println!("  ✏️ 이메일 업데이트: {}", self.email);
        }

        pub fn celebrate_birthday(&mut self) {
            self.age += 1;
            println!("  🎉 생일을 축하합니다! 이제 {}살입니다.", self.age);
        }
    }

    pub fn demonstrate() {
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!("📚 섹션 3: 여러 impl 블록");
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

        println!("1️⃣ 생성 관련 impl 블록:");
        let user1 = User::new("alice", "alice@example.com", 25);
        let user2 = User::from_username("bob");
        println!("   ✅ 여러 생성자 패턴\n");

        println!("2️⃣ 정보 조회 impl 블록:");
        user1.display_info();
        println!("   어른인가? {}\n", user1.is_adult());

        println!("3️⃣ 수정 impl 블록:");
        let mut user3 = User::new("carol", "carol@old.com", 20);
        user3.update_email("carol@new.com");
        user3.celebrate_birthday();
        println!("");
    }
}

/// 섹션 4: 데이터 검증과 메서드
///
/// 메서드 내에서 데이터 유효성 검사
/// 불변 조건(invariant) 유지
mod section_4_validation {
    pub struct BankAccount {
        owner: String,
        balance: f64,
    }

    impl BankAccount {
        pub fn new(owner: &str, initial_balance: f64) -> BankAccount {
            BankAccount {
                owner: String::from(owner),
                balance: if initial_balance >= 0.0 {
                    initial_balance
                } else {
                    0.0  // 음수 잔액 방지
                },
            }
        }

        pub fn get_balance(&self) -> f64 {
            self.balance
        }

        pub fn deposit(&mut self, amount: f64) -> Result<(), String> {
            if amount <= 0.0 {
                Err(String::from("입금액은 0보다 커야 합니다"))
            } else {
                self.balance += amount;
                println!("  ✅ {}원 입금됨. 잔액: {}", amount, self.balance);
                Ok(())
            }
        }

        pub fn withdraw(&mut self, amount: f64) -> Result<(), String> {
            if amount <= 0.0 {
                Err(String::from("출금액은 0보다 커야 합니다"))
            } else if amount > self.balance {
                Err(String::from("잔액이 부족합니다"))
            } else {
                self.balance -= amount;
                println!("  ✅ {}원 출금됨. 잔액: {}", amount, self.balance);
                Ok(())
            }
        }

        pub fn display(&self) {
            println!("  계좌: {}, 잔액: {}원", self.owner, self.balance);
        }
    }

    pub fn demonstrate() {
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!("📚 섹션 4: 데이터 검증과 메서드");
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

        let mut account = BankAccount::new("Claude", 10000.0);
        account.display();

        println!("\n1️⃣ 정상 입금:");
        let _ = account.deposit(5000.0);

        println!("\n2️⃣ 정상 출금:");
        let _ = account.withdraw(3000.0);

        println!("\n3️⃣ 잘못된 입금 (음수):");
        match account.deposit(-1000.0) {
            Ok(_) => println!("  입금 성공"),
            Err(e) => println!("  ❌ 오류: {}", e),
        }

        println!("\n4️⃣ 잘못된 출금 (잔액 초과):");
        match account.withdraw(20000.0) {
            Ok(_) => println!("  출금 성공"),
            Err(e) => println!("  ❌ 오류: {}", e),
        }

        account.display();
        println!("");
    }
}

/// 섹션 5: 메서드와 함수의 관계
///
/// 메서드 vs 함수
/// - 메서드: impl 블록 내에서 self를 가짐
/// - 함수: 독립적인 함수, self 없음
mod section_5_methods_vs_functions {
    pub struct Rectangle {
        pub width: f32,
        pub height: f32,
    }

    impl Rectangle {
        // 메서드: impl 블록 내, self 사용
        pub fn area(&self) -> f32 {
            self.width * self.height
        }

        pub fn can_hold(&self, other: &Rectangle) -> bool {
            self.width > other.width && self.height > other.height
        }

        pub fn scale(&mut self, factor: f32) {
            self.width *= factor;
            self.height *= factor;
        }
    }

    // 함수: impl 블록 외, self 없음
    pub fn create_square(size: f32) -> Rectangle {
        Rectangle {
            width: size,
            height: size,
        }
    }

    pub fn demonstrate() {
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!("📚 섹션 5: 메서드와 함수의 관계");
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

        println!("1️⃣ 함수로 생성:");
        let mut rect1 = create_square(5.0);
        println!("   정사각형 생성: {}x{}\n", rect1.width, rect1.height);

        println!("2️⃣ 메서드로 정보 조회:");
        println!("   면적: {}", rect1.area());

        println!("\n3️⃣ 다른 메서드 호출:");
        let rect2 = Rectangle { width: 3.0, height: 4.0 };
        println!("   rect1이 rect2를 포함할 수 있나? {}",
                 rect1.can_hold(&rect2));

        println!("\n4️⃣ &mut self 메서드:");
        rect1.scale(2.0);
        println!("   스케일 2배: {}x{}", rect1.width, rect1.height);
        println!("   새 면적: {}\n", rect1.area());
    }
}

/// 섹션 6: 생성자 패턴
///
/// new() 관례와 빌더 패턴의 기초
mod section_6_constructors {
    pub struct Config {
        pub host: String,
        pub port: u16,
        pub debug: bool,
        pub timeout: u32,
    }

    impl Config {
        // 패턴 1: 기본 new()
        pub fn new() -> Config {
            Config {
                host: String::from("localhost"),
                port: 8080,
                debug: false,
                timeout: 30,
            }
        }

        // 패턴 2: 매개변수가 있는 new()
        pub fn from_host_port(host: &str, port: u16) -> Config {
            Config {
                host: String::from(host),
                port,
                debug: false,
                timeout: 30,
            }
        }

        // 패턴 3: 빌더의 시작 (메서드 체이닝)
        pub fn with_debug(mut self, debug: bool) -> Self {
            self.debug = debug;
            self
        }

        pub fn with_timeout(mut self, timeout: u32) -> Self {
            self.timeout = timeout;
            self
        }

        pub fn display(&self) {
            println!("  🔧 호스트: {}:{}", self.host, self.port);
            println!("  🐛 디버그: {}", self.debug);
            println!("  ⏱️ 타임아웃: {}초", self.timeout);
        }
    }

    pub fn demonstrate() {
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        println!("📚 섹션 6: 생성자 패턴");
        println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

        println!("1️⃣ 기본 new():");
        let config1 = Config::new();
        config1.display();

        println!("\n2️⃣ from_host_port():");
        let config2 = Config::from_host_port("example.com", 443);
        config2.display();

        println!("\n3️⃣ 빌더 패턴 (메서드 체이닝):");
        let config3 = Config::new()
            .with_debug(true)
            .with_timeout(60);
        config3.display();
        println!("");
    }
}

/// 섹션 7: 종합 예제 — 지능형 시스템
///
/// v5.0 + v5.1의 모든 개념을 종합한 실전 예제
mod section_7_advanced_example {
    #[derive(Debug)]
    pub struct IntelligentSystem {
        name: String,
        version: f32,
        is_running: bool,
        uptime_seconds: u64,
        task_count: u32,
    }

    impl IntelligentSystem {
        // 연관 함수: 생성자
        pub fn new(name: &str, version: f32) -> IntelligentSystem {
            IntelligentSystem {
                name: String::from(name),
                version,
                is_running: false,
                uptime_seconds: 0,
                task_count: 0,
            }
        }

        // &self: 정보 조회
        pub fn status(&self) {
            let status_text = if self.is_running { "🟢 실행 중" } else { "⚫ 중지됨" };
            println!("  [{}] v{} {}", self.name, self.version, status_text);
            println!("    └─ 부하: {} 작업, 가동 시간: {}초",
                     self.task_count, self.uptime_seconds);
        }

        pub fn get_health(&self) -> String {
            if !self.is_running {
                String::from("시스템 중지됨")
            } else if self.task_count > 100 {
                String::from("과부하 상태")
            } else {
                String::from("정상")
            }
        }

        // &mut self: 상태 수정
        pub fn start(&mut self) {
            self.is_running = true;
            println!("  ✅ '{}' 시스템 시작", self.name);
        }

        pub fn add_task(&mut self) -> Result<(), String> {
            if !self.is_running {
                Err(String::from("시스템이 실행 중이지 않습니다"))
            } else if self.task_count >= 200 {
                Err(String::from("최대 작업 수 초과"))
            } else {
                self.task_count += 1;
                println!("  ➕ 작업 추가됨 (총: {})", self.task_count);
                Ok(())
            }
        }

        pub fn tick(&mut self) {
            if self.is_running {
                self.uptime_seconds += 1;
            }
        }

        // self: 최종 작업 (소유권 이전)
        pub fn shutdown(self) {
            println!("  ❌ '{}' 시스템 종료", self.name);
            println!("     총 가동 시간: {}초", self.uptime_seconds);
            println!("     최대 작업: {}", self.task_count);
        }
    }

    pub fn demonstrate() {
